solution_code:
#include <iostream>
#include <string>

int main() {
    std::string name{};
    int age{};

    std::cin >> name >> age;

    std::cout << "Hello, " << name << "! You are " << age << " years old." << '\n';
    std::cout << "Next year you will be " << age + 1 << '.' << '\n';

    return 0;
}
